import React, { useState } from 'react';
import { Target, AlertCircle, CheckCircle } from 'lucide-react';

const BudgetSettings = () => {
  const [budgets, setBudgets] = useState({
    monthly: 3000,
    food: 500,
    transport: 300,
    entertainment: 200,
    shopping: 400
  });

  const [actualSpending, setActualSpending] = useState({
    food: 320,
    transport: 280,
    entertainment: 150,
    shopping: 350
  });

  const handleBudgetChange = (category, value) => {
    setBudgets(prev => ({
      ...prev,
      [category]: parseFloat(value) || 0
    }));
  };

  const getBudgetStatus = (category) => {
    const spent = actualSpending[category] || 0;
    const budget = budgets[category] || 0;
    const percentage = budget > 0 ? (spent / budget) * 100 : 0;
    
    if (percentage >= 90) return 'over';
    if (percentage >= 75) return 'warning';
    return 'good';
  };

  return (
    <div className="budget-settings">
      <h3><Target size={20} /> Budget Settings</h3>
      
      <div className="budget-cards">
        {Object.entries(budgets).map(([category, amount]) => {
          if (category === 'monthly') return null;
          
          const status = getBudgetStatus(category);
          const spent = actualSpending[category] || 0;
          const percentage = amount > 0 ? (spent / amount) * 100 : 0;
          
          return (
            <div key={category} className={`budget-card ${status}`}>
              <div className="budget-header">
                <span className="category">{category}</span>
                <span className="amount">${amount}</span>
              </div>
              <div className="progress-bar">
                <div 
                  className="progress-fill"
                  style={{ width: `${Math.min(percentage, 100)}%` }}
                ></div>
              </div>
              <div className="budget-footer">
                <span>Spent: ${spent}</span>
                <span>{percentage.toFixed(1)}%</span>
              </div>
              {status === 'over' && (
                <div className="budget-alert">
                  <AlertCircle size={14} />
                  Over budget!
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default BudgetSettings;
